troller_heavy_groups","travelers_wanting_mostly_indoor_sightseeing"]},"walking_notes":["Overall walking is moderate for a bus tour rather than a trekking itinerary.","1100 Highland, Jusangjeolli, O’sulloc, and Aewol are manageable for most travelers under normal conditions.","Cheonjeyeon is the stop with the most noticeable walking load because of steps and forest-path movement.","Comfortable grip shoes are strongly recommended, especially in wet, windy, or colder conditions."],"keywords":["southwest jeju bus tour","jeju 1100 highland osulloc aewol tour","jusangjeolli cheonjeyeon bus day tour","jungmun osulloc aewol sightseeing bus","best value southwest jeju tour","first time jeju southwest day trip","jeju tea museum and aewol coast tour","1100 highland jeju day tour","cheonjeyeon waterfall bus tour","jeju scenic southwest route"],"synonym_hints":["southwest jeju highlights by bus","1100 highland to aewol day route","jungmun waterfall cliff tea field tour","budget-friendly southwest jeju tour","aewol cafe coast finish bus tour","fixed pickup jeju bus tour"],"profile_version":1,"is_active":true},"matching_metadata":{"matching_schema":"tour_matching_profiles_embedded_v1","embedded_for":["authoring","review","sql_backfill_reference"],"note":"Scores were tuned for a scenic Southwest Jeju bus-tour format: very high scenery and photo fit, stronger couple/café/relax value than the South classic route, moderate walking overall, and weather sensitivity driven mainly by 1100 Highland visibility plus exposed coastal sections.","duration_hours":10,"stop_count":6},"pickup_dropoff":{"pickupType":"fixed_meeting_points","dropoffType":"fixed_dropoff_points","departure":[{"order":1,"time":"08:30","name":"Ocean Suites Hotel","type":"hotel","note":"Main city pickup point near Tapdong."},{"order":2,"time":"08:45","name":"Jeju Airport, 3rd Floor Gate 3","type":"airport","note":"Departure floor meeting point."},{"order":3,"time":"08:55","name":"Lotte City Hotel Jeju","type":"hotel","note